            </a>\r\n              ) : (\r\n                  <Link\r\n                      key={link.name}\r\n                      href={link.href}\r\n                      className=\"text-white hover:text-white/50 transition-colors\"\r\n                  >\r\n                      {link.name}\r\n                  </Link>\r\n              )\r\n          ))}\r\n      </nav>\r\n\r\n\r\n            <button\r\n                onClick={toggleMenu}\r\n                className=\"relative md:hidden flex flex-col justify-center items-center w-8 h-8 gap-1.5 z-110 focus:outline-none cursor-pointer\"\r\n                aria-label=\"Toggle Menu\"\r\n            >\r\n                <span className={`h-0.5 w-full bg-white transition-all duration-300 ${isOpen ? 'rotate-45 translate-y-2' : ''}`}></span>\r\n                <span className={`h-0.5 w-full bg-white transition-all duration-300 ${isOpen ? 'opacity-0' : ''}`}></span>\r\n                <span className={`h-0.5 w-full bg-white transition-all duration-300 ${isOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>\r\n            </button>\r\n\r\n            {/* Navigation Mobile */}\r\n            <div className={`fixed inset-0 bg-black z-105 flex flex-col items-center justify-center transition-transform duration-500 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>\r\n                <nav className=\"flex flex-col gap-10 text-center\">\r\n                    {navLinks.map((link) => (\r\n                        link.href.startsWith('http') ? (\r\n                            <a\r\n                                key={link.name}\r\n                                href={link.href}\r\n                                target=\"_blank\"\r\n                                rel=\"noopener noreferrer\"\r\n                                onClick={toggleMenu}\r\n                                className=\"text-3xl font-normal text-white tracking-widest hover:scale-110 transition-transform\"\r\n                            >\r\n                                {link.name}\r\n                            </a>\r\n                        ) : (\r\n                            <Link\r\n                                key={link.name}\r\n                                href={link.href}\r\n                                onClick={toggleMenu}\r\n                                className=\"text-3xl font-normal text-white tracking-widest hover:scale-110 transition-transform\"\r\n                            >\r\n                                {link.name}\r\n                            </Link>\r\n                        )\r\n                    ))}\r\n                </nav>\r\n\r\n                <div className=\"absolute bottom-12 text-white/60 text-[10px] tracking-widest\">\r\n                    A Play To Sky Group Entity\r\n                </div>\r\n            </div>\r\n        </header>\r\n    );\r\n}"],"names":["Header","isOpen","setIsOpen","toggleMenu","navLinks","name","href","className","src","alt","width","height","unoptimized","map","link","startsWith","target","rel","onClick"],"mappings":";;;;;AAEA;AACA;AACA;;;AAJA;;;;AAMe,SAASA;;IACpB,MAAM,CAACC,QAAQC,UAAU,GAAG,IAAA,yKAAQ,EAAC;IAErC,MAAMC,aAAa,IAAMD,UAAU,CAACD;IAEpC,MAAMG,WAAW;QACb;YAAEC,MAAM;YAAaC,MAAM;QAAyB;QACpD;YAAED,MAAM;YAASC,MAAM;QAAS;QAChC;YAAED,MAAM;YAAWC,MAAM;QAAW;QACpC;YAAED,MAAM;YAAWC,MAAM;QAAW;KACvC;IAED,qBACI,6LAAC;QAAOC,WAAU;;0BAEd,6LAAC;gBAAIA,WAAU;0BACX,cAAA,6LAAC,0KAAI;oBAACD,MAAK;8BACP,cAAA,6LAAC,2IAAK;wBACFE,KAAI;wBACJC,KAAI;wBACJC,OAAO;wBACPC,QAAQ;wBACRC,WAAW;wBACXL,WAAU;;;;;;;;;;;;;;;;0BAM5B,6LAAC;gBAAIA,WAAU;0BACVH,SAASS,GAAG,CAAC,CAACC,OACXA,KAAKR,IAAI,CAACS,UAAU,CAAC,wBACjB,6LAAC;wBAEGT,MAAMQ,KAAKR,IAAI;wBACfU,QAAO;wBACPC,KAAI;wBACJV,WAAU;kCAETO,KAAKT,IAAI;uBANLS,KAAKT,IAAI;;;;6CASlB,6LAAC,0KAAI;wBAEDC,MAAMQ,KAAKR,IAAI;wBACfC,WAAU;kCAETO,KAAKT,IAAI;uBAJLS,KAAKT,IAAI;;;;;;;;;;0BAWxB,6LAAC;gBACGa,SAASf;gBACTI,WAAU;gBACV,cAAW;;kCAEX,6LAAC;wBAAKA,WAAW,CAAC,kDAAkD,EAAEN,SAAS,4BAA4B,IAAI;;;;;;kCAC/G,6LAAC;wBAAKM,WAAW,CA